<template>
    <div class="datamanager_base_nfo">
        <Row class="base_info_index">
            <RadioGroup v-model="isCollapsed" type="button">
                <Radio label="成绩检测" :style="{margin:'0 10px',borderRadius:'5px',border:'1px solid #eee'}">成绩检测</Radio>
            </RadioGroup>
        </Row>
        <Row style='height:90%'>
            <div v-if="isCollapsed=='成绩检测'">
                <gradeInfo />
            </div>
        </Row>
    </div>
</template>
<script>
import gradeInfo from "@/components/DataManager/gradeInfo"
export default {
    data () {
        return {
            isCollapsed: "成绩检测"
        }
    },
    components:{
        gradeInfo,
    },
    methods:{
        updat(el){
        }
    },
    watch:{
        isCollapsed(news){
            if(news=="鉴权"){
                this.$store.commit("chooseNgiax",null)
            }
        }
    }

}
</script>
<style scoped>
.datamanager_base_nfo{
    height:100%;
}
.base_info_index{
   border-bottom: 1px solid #eee; 
   margin-bottom: 20px;
}
.ivu-radio-wrapper:after{
    width:0px !important;
}
.ivu-radio-wrapper:before{
    border:0px solid red !important;
    width:0px !important;
}
.ivu-radio-wrapper-checked{
    box-shadow:0 0 0 0 #aaa !important;
}
</style>





