<template>
    <div>
        <Row :style="{marginTop:'20px'}">
            <Col span="3" offset="1" style="font-size:14px;font-weight:700">
                成绩单输入 :
            </Col>
        </Row>
        <Row :style="{marginTop:'20px'}">
            <Col span="12" offset='3' :style="{overflow:'hidden'}">
                <v-table
                    is-horizontal-resize
                    column-width-drag
                    style="width:100%"
                    :columns="columns"
                    :table-data="subtabs"
                    row-hover-color="#eee"
                    row-click-color="#edf7ff"
                    :cell-edit-done="cellEditDone"
                ></v-table>
            </Col>
        </Row>
        <Row :style="{lineHeight:'30px'}">
            <Col span="4" offset='3' :style="{textAlign:'center',fontSize:'25px',color:'red'}">
                <Icon type="ios-add" class="orderIndex_add_icon" @click="addIcon"/>
            </Col>
        </Row>
    </div>
</template>
<script>
export default {
    data(){
        return{
            msg:"成绩输入",
            tableData:[{class:'数学',grade:"100",full_mark:"100"}],
            columns: [
                {field: 'class', title: '科目', width: 100, titleAlign: 'center', columnAlign: 'center',isResize:true,isEdit:true,},
                {field: 'grade', title: '成绩', width: 100, titleAlign: 'center', columnAlign: 'center',isResize:true,isEdit:true,},
                {field: 'full_mark', title: '科目总分', width: 100, titleAlign: 'center', columnAlign: 'center',isResize:true,isEdit:true,},
            ]
        }
    },
    props:['subtabs'],
    methods:{
        // 单元格编辑回调
        cellEditDone(newValue,oldValue,rowIndex,rowData,field){
            this.subtabs[rowIndex][field] = newValue;
        },
        // 单元格添加
        addIcon(){
            var that = this
            var addMsg = {class:'',grade:"",full_mark:""}
            var readyMsg = JSON.parse(JSON.stringify(addMsg))
            if(that.subtabs.length>=1){
                var lastInfo =that.subtabs[that.subtabs.length-1]
                if(lastInfo.grade==''||lastInfo.full_mark==''){
                    that.$Message.info("请完善科目成绩")
                }else{
                    that.subtabs.splice(that.subtabs.length,0,readyMsg)
                }
            }else{
                that.subtabs.splice(that.subtabs.length,0,readyMsg)
            }
        },
    }
}
</script>



