<template>
    <div class="layout">
        <Layout>
            <Header class="bloder">
                <Menu mode="horizontal" theme="dark" active-name="1" class="bloder">
                    <div class="layout-logo">
                        春节过年 · 成绩检测系统
                    </div>
                    <div class="layout-nav">
                        <MenuItem name="1">
                            <Icon type="ios-navigate"></Icon>
                             杨冰冰
                        </MenuItem>
                    </div>
                </Menu>
            </Header>
            <Layout class="homediv">
                <Sider ref="side1" hide-trigger collapsible :collapsed-width="78" v-model="isCollapsed">
                <Menu :active-name="activeName" theme="dark" width="auto" :class="menuitemClasses" @on-select="routerLink">
                    <MenuItem name="1-1">
                        <Icon type="ios-navigate"></Icon>
                        <span>压岁奖励</span>
                    </MenuItem>
                    <MenuItem name="1-2">
                        <Icon type="ios-search"></Icon>
                        <span>总结汇总</span>
                    </MenuItem>
                </Menu>
            </Sider>
            <Layout>
                <Header :style="{padding: 0,height:'50px',lineHeight:'50px'}" class="layout-header-bar">
                    <Icon @click.native="collapsedSider" :class="rotateIcon" :style="{margin: '0 20px'}" type="md-menu" size="24"></Icon>
                    <Breadcrumb :style="{display:'inline-block'}">
                        <BreadcrumbItem>{{inlineClick}}</BreadcrumbItem>
                    </Breadcrumb>
                </Header>
                <Content :style="{ borderTop:'1px solid #eee',background: '#fff', height: '100%',minWidth: '800px',padding:'18px 15px 0'}" v-if='routerInL'>
                    <keep-alive>
                        <router-view></router-view>
                    </keep-alive>
                </Content>
                <Content :style="{ borderTop:'1px solid #eee',background: '#fff', height: '100%',minWidth: '800px',padding:'18px 15px 0'}" v-else>
                    <router-view></router-view>
                </Content>
            </Layout>
            </Layout>
        </Layout>
    </div>
</template>
<script>
    export default {
        data () {
            return {
                isCollapsed: false,
                // 左边点击
                inlineClick:"",
                // 右边点击
                activeName:"",
                routerInL:true

            }
        },
       
        created(){
            var that =this
            // 路由拦截
            this.$router.beforeEach((to, from, next) => {
                if(to.name=='reqDemandBaseControl'||to.name=='demand_report_info'){
                    that.routerInL = false
                }
                next();
            });
            
            if(this.$route.path=='/'){
                this.$router.push({name:'DataManagerBaseIndex'})
                this.activeName ="1-1"
            }
            if(this.$route.path=='/Home/DataManagerBaseIndex'){
                this.inlineClick = '压岁奖励'
                this.activeName ="1-1"
            }
            if(this.$route.path=='/Home/baseControl'){
                this.inlineClick = '总结汇总'
                this.activeName ="1-2"

            }
            
        },
        components:{
        },
        computed: {
            rotateIcon () {
                return [
                    'menu-icon',
                    this.isCollapsed ? 'rotate-icon' : ''
                ];
            },
            menuitemClasses () {
                return [
                    'menu-item',
                    this.isCollapsed ? 'collapsed-menu' : ''
                ]
            }
        },
        methods: {
            collapsedSider () {
                this.$refs.side1.toggleCollapse();
            },
            routerLink(el){
                if(el == '1-1'){
                    this.$router.push({name:'DataManagerBaseIndex'})
                    this.inlineClick = "压岁奖励"
                }
                if(el == '1-2'){
                    this.$router.push({name:'baseControl'})
                    this.inlineClick = "总结汇总"
                }
                
            }
        }
    }
</script>
<style scoped>

.layout-nav{
    width: 120px;
    margin: 0 auto;
    margin-right: 20px;
}
.ivu-layout-sider-children{
    
}
.ivu-layout-content{
    overflow-y: scroll !important;
}
.layout{
    /* border: 1px solid #d7dde4; */
    background: #f5f7f9;
    position: relative;
    /* border-radius: 4px; */
    overflow: hidden;
    height: 100%;
    display: FLEX;
}

.layout-header-bar{
    background: #fff;
    box-shadow: 0 1px 1px rgba(0,0,0,.1);
}
.layout-logo-left{
    width: 90%;
    height: 30px;
    border-radius: 3px;
    margin: 15px auto;
}
.menu-icon{
    transition: all .3s;
}
.ivu-layout{
    height:100%;
}
.rotate-icon{
    transform: rotate(-90deg);
}
.bloder{
    line-height: 50px !important;
    background-color: rgb(29, 29, 34) !important;
}
.ivu-layout-header{
    height:50px !important;
}
.ivu-menu{
    height:50px !important;
}
.layout-logo{
    width: 230px;
    height: 60px;
    line-height: 50px;
    color:#fff;
    font-size: 18px;
    border-radius: 3px;
    font-weight: 700;
    float: left;
    position: relative;
    top: 0px;
    left: 20px;
}
.ivu-layout-sider{
    background:#001529 !important;
}
.menu-item{
    background-color: #001529 !important;
}
.menu-item span{
    display: inline-block;
    overflow: hidden;
    width: 100px;
    text-overflow: ellipsis;
    white-space: nowrap;
    vertical-align: bottom;
    color:#fff;
    font-weight: 700;
    transition: width .2s ease .2s;
}
.menu-item i{
    transform: translateX(0px);
    transition: font-size .2s ease, transform .2s ease;
    vertical-align: middle;
    font-size: 18px;
}
.collapsed-menu span{
    width: 0px;
    transition: width .2s ease;
}
.collapsed-menu i{
    transform: translateX(5px);
    transition: font-size .2s ease .2s, transform .2s ease .2s;
    vertical-align: middle;
    font-size: 22px;
}
</style>


