<template>
    <div>
        <Row :style="{marginTop:'20px'}">
            <grade :subtabs="gradeInfo"/>
        </Row>
        <Row :style="{marginTop:'20px'}">
            <calculate :subtabs="gradeInfo"/>
        </Row>
    </div>
</template>
<script>
import grade from "@/components/DataManager/gradeInfo/grade"
import calculate from "@/components/DataManager/gradeInfo/calculate"
export default {
    data(){
        return{
            msg:"成绩自动计算系统",
            gradeInfo:[{class:'数学',grade:"100",full_mark:"100"}]
        }
    },
    components:{
        grade,
        calculate
    },
    created(){
        this.gradeInfo=[]
    }
}
</script>



