<template>
    <div>
        <Row :style="{marginTop:'10px'}">
            <Col span="2" offset="1" style="text-align:center;font-size:14px;font-weight:700;line-height:25px">
                成绩检测 :
            </Col>
            <Col span="15">
                <Button :style="{width:'80px',marginRight:'10px',height:'25px',paddingTop:'2px'}" shape="circle"  @click="checkInfo">开始检测</Button>
            </Col>
        </Row>
        <Row style='margin-left:80px;margin-top:20px'>
            <Row :style="{marginTop:'10px'}">
                <Col span="3" offset="1" style="text-align:center;font-size:14px;font-weight:900;line-height:25px">
                    奖励项目 
                </Col>
                <Col span="3" offset="1" style="text-align:center;font-size:14px;font-weight:900;line-height:25px">
                    验证结果 
                </Col>
                <Col span="3" offset="1" style="text-align:center;font-size:14px;font-weight:900;line-height:25px">
                    计算(元) 
                </Col>
            </Row>
            <Row :style="{marginTop:'10px'}">
                <Col span="3" offset="1" style="font-weight:700;text-align:center;font-size:14px;line-height:25px">
                    科目达标 :
                </Col>
                <Col span="3" offset="1" style="text-align:center;font-size:14px;line-height:25px">
                    {{dabiao.info}} 
                </Col>
                <Col span="3" offset="1" style="text-align:center;font-size:14px;line-height:25px">
                    {{dabiao.ngix}}  
                </Col>
            </Row>
            <Row :style="{marginTop:'10px'}">
                <Col span="3" offset="1" style="font-weight:700;text-align:center;font-size:14px;line-height:25px">
                    最低分科目 :
                </Col>
                <Col span="3" offset="1" style="text-align:center;font-size:14px;line-height:25px">
                    {{lowObj.info}} 
                </Col>
                <Col span="3" offset="1" style="text-align:center;font-size:14px;line-height:25px">
                    {{lowObj.ngix}}  
                </Col>
            </Row>
            <Row :style="{marginTop:'10px'}">
                <Col span="3" offset="1" style="font-weight:700;text-align:center;font-size:14px;line-height:25px">
                    最高分科目达标 :
                </Col>
                <Col span="3" offset="1" style="text-align:center;font-size:14px;line-height:25px">
                    {{hotObj.info}} 
                </Col>
                <Col span="3" offset="1" style="text-align:center;font-size:14px;line-height:25px">
                    {{hotObj.ngix}}  
                </Col>
            </Row>
            <Row :style="{marginTop:'10px'}">
                <Col span="3" offset="1" style="font-weight:700;text-align:center;font-size:14px;line-height:25px">
                    总分达标 :
                </Col>
                <Col span="3" offset="1" style="text-align:center;font-size:14px;line-height:25px">
                    {{fullObj.info}} 
                </Col>
                <Col span="3" offset="1" style="text-align:center;font-size:14px;line-height:25px">
                    {{fullObj.ngix}}  
                </Col>
            </Row>
            <Row :style="{marginTop:'10px',marginBottom:'30px'}">
                <Col span="3" offset="1" style="font-weight:700;text-align:center;font-size:14px;line-height:25px">
                    合计 :
                </Col>
                
                <Col span="3" offset="5" style="text-align:center;font-size:14px;line-height:25px">
                    {{fullMoney}}
                </Col>
            </Row>
        </Row>
    </div>
</template>
<script>
export default {
    data(){
        return{
            msg:"计算成绩",
            // 科目达标
            dabiao:{info:"",ngix:""},
            // 最低分科目
            lowObj:{info:"",ngix:""},
            // 最高分科目达标
            hotObj:{info:"",ngix:""},
            // 总分达标
            fullObj:{info:"",ngix:""},
            // 是否初三/高三
            lastObj:{info:"",ngix:""},
            // 是否本命年
            myObj:{info:"",ngix:""},
            fullMoney:""

        }
    },
    props:['subtabs'],
    methods:{
        checkInfo(){
            var that = this
            var info = this.subtabs
            info = JSON.parse(JSON.stringify(info))
            info = info.filter(val=>val.full_mark!==''&&val.grade!=='')
            info.map(val=>{
                val.grade = parseInt(val.grade/val.full_mark*100)
            })
            // 科目达标
            var count=0
            var unit = true
            info.map(val=>{
                if(val.grade<30){
                    count+=1
                }
            })
            if(count==info.length-1)unit=false
            if(unit){
                this.dabiao.info= '达标'
                info = JSON.parse(JSON.stringify(info))
                var icex = info.sort(that.compare('grade'))
                // 最低分
                this.lowObj.ngix = icex[0].grade
                this.lowObj.info = icex[0].class
                // 最高分
                this.hotObj.info = (100-(icex[icex.length-1].grade))<=5?'达标':'未达标'
                this.hotObj.ngix = this.hotObj.info=='达标'?50:0
                // 总分达标
                var mmp=0
                info.map(item =>{
                    mmp +=item.grade
                })
                this.fullObj.info = (icex.length*100)-mmp<100?'达标':'未达标'
                this.fullObj.ngix = this.fullObj.info=='达标'?(icex.length*100-100):0

                this.fullMoney = this.fullObj.ngix+this.hotObj.ngix+this.lowObj.ngix
                console.log(mmp,this.fullMoney)
            }else{
                this.fullMoney = 20
            }

        },
        // 排序
        compare(property){
            return function(a,b){
                var value1 = a[property];
                var value2 = b[property];
                return value1 - value2;
            }
        }
    }
}
</script>



